#include <stdio.h>

int countDigits(int n){
    if(n==0) return 1;
    int cnt=0;
    while(n>0){cnt++; n/=10;}
    return cnt;
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int d = countDigits(N);
        long long sum = 0;
        int temp = N;
        if(N==0){
            sum = 0; // 0^1 = 0
        }else{
            while(temp>0){
                int digit = temp%10;
                long long p = 1;
                for(int i=0;i<d;i++) p *= digit;
                sum += p;
                temp/=10;
            }
        }
        printf("%s\n", sum==N?"YES":"NO");
    }
    return 0;
}

